INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('f54bb682-0d21-4cf8-9cdc-aa4668642ec7', NULL, '15 CONSEJOS PARA BUSCAR EMPLEO', '15 Consejos para Sobrellevar el Paro No es nada fácil estar en paro. Es estresante, socava la autoestima y, la falta de estabilidad financiera, provoca angustia ante la incertidumbre del futuro. Cuanto más se prolonga el desempleo, más aumenta la desesperanza. Sin embargo, hay varias cosas que podemos hacer para mantener la motivación y hacer más llevadero el arduo camino de la búsqueda de trabajo. A continuación mostramos una lista de 15 consejos para mantenerse activo en paro y no caer en la depresión: 1. Cíñete a un horario. Acuéstate y levántate a la misma hora cada día. Considera la búsqueda de empleo como un trabajo en sí mismo y asegúrate de que cada día llegas a él a tiempo. Al salir del “trabajo” del día, haz algo diferente y deja de centrarte en la búsqueda de empleo por unas horas. 2. Rodéate de personas con trabajo. Puede parecer contradictorio, pero es más útil que juntarse con otros desempleados y compadecerse. Eso nos arrastra hacia el fondo. Procura pasar el tiempo con personas con trabajo. No solo te subirá el ánimo, sino que te pueden proporcionar pistas para encontrar trabajo. 3. Aprende algo nuevo. Acepta el reto de aprender algo que siempre has querido aprender pero para lo que nunca tuviste tiempo. Enfrentarte a este reto te mantendrá ocupado y aumentará la confianza en tí mismo. 4. Haz algún curso relacionado con tu trabajo. Esto mejorará tu currículum y te mantendrá ocupado al mismo tiempo. Busca cursos gratuitos para desempleados en tu campo de trabajo. 5. Respira, repite afirmaciones positivas. Muchas personas niegan la importancia de las técnicas de relajación, de la respiración o de la búsqueda consciente de la felicidad porque les parece algo cursi o que no sirve para nada. Sin embargo, funciona. Las afirmaciones voz alta o dedicar diez minutos por día para la respiración consciente te harán sentir mejor. 6. Evita las malas noticias. Las noticias sobre desahucio y tasas de desempleo no son buenas para ti en este momento. Las malas noticias producen un efecto negativo sobre nosotros. Lee un libro edificante o ve buenas películas en su lugar. 7. Haz ejercicio todos los días. Treinta minutos de ejercicio al día nos hacen sentir mejor física y mentalmente. El ejercicio moderado al aire libre aumenta las endorfinas también conocidas como hormonas de la felicidad. 8. Cuida la alimentación. De nuevo, los beneficios físicos redundan en el estado de la mente. Una alimentación sana y equilibrada nos hace sentir mejor. 9. Esfuérzate en hablar de lo que estás haciendo. Es fácil centrarse en hablar de lo frustrante que es buscar trabajo o de lo mal que está la situación económica. Es contraproducente y solo sirve para hundirnos más. Habla sobre lo que has estado haciendo, lo que has leído, lo que querías ser cuando eras un niño… Cualquier cosa positiva excepto de la búsqueda de trabajo. 10. Apóyate en las personas de tu confianza. Cuando los sentimientos negativos te abrumen, no te encierres. Ábrete a las personas de tu entorno que sean mejor apoyo en tiempos de difíciles. Estas personas no tienen porqué ser tu pareja o tu mejor amigo. Un amigo con menos implicación en tu bienestar puede ser un mejor oído en este momento. 11. Celebra las pequeñas cosas. La entrevista de trabajo quizá no ha salido bien, pero, al menos, has tenido una entrevista. Es difícil mantener una actitud positiva, pero hay que pensar que el esfuerzo que has realizado para hacerlo bien ya vale la pena. 12. Ponte metas diarias específicas. El mundo laboral en este momento está complicado, pero tú puedes alcanzar metas diarias relacionadas con la búsqueda de empleo. Establece unos objetivos diarios de búsqueda de empleo y cúmplelos. Tu autoestima se verá recompensada. 13. Haz un presupuesto. Esto puede ser frustrante cuando no hay ingresos pero, por lo menos, te da una cierta sensación de control sobre tus finanzas, lo cual puede hacerte sentir mejor a largo plazo. 14. Ve a algún lugar, a cualquiera, todos los días. Es muy fácil deprimirse quedándose en casa. Ve a tomar un café a un bar, a mirar escaparates o a dar una vuelta a la manzana. Para no caer en la depresión hay que esforzarse en hacer lo contrario a lo que apetece: hablar, salir, divertirse…. 15. No descartar la ayuda de un profesional. Si estás comenzando a sufrir depresión a causa del desempleo plantéate la posibilidad de buscar la ayuda de un psicólogo o un psiquiatra. Harán que te sientas mejor. Comparto una app autoayuda', 'https://erbolamm.blogspot.com/2020/09/app-es-feliz-no-me-descargue.html', 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEh5WBbcre9_DsSE9ANlCjFb1gpKfOffsCzq8pwiebJ3Bn2rT-B3Rb7COyXz6rwMZDwND4M3UGIod76xnWr6EehJAQl1SEatIQriHiPPeI13AwqzNfw3EnoYIJPeWGne-5RCLgUfiAyzBXFj8TFPKRCzBktjeOXaOqUsiSNVeQs-THP2548PhfFH0AqH_w/w128-h128-p-k-no-nu/VIST%20APREVIA.png', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('ce750e50-5b0a-44eb-8212-8b74550207e8', NULL, '15 CONSEJOS PARA SOBRELLEVAR EL PARO', '15 Consejos para Sobrellevar el Paro No es nada fácil estar en paro. Es estresante, socava la autoestima y, la falta de estabilidad financiera, provoca angustia ante la incertidumbre del futuro. Cuanto más se prolonga el desempleo, más aumenta la desesperanza. Sin embargo, hay varias cosas que podemos hacer para mantener la motivación y hacer más llevadero el arduo camino de la búsqueda de trabajo. A continuación mostramos una lista de 15 consejos para mantenerse activo en paro y no caer en la depresión: 1. Cíñete a un horario. Acuéstate y levántate a la misma hora cada día. Considera la búsqueda de empleo como un trabajo en sí mismo y asegúrate de que cada día llegas a él a tiempo. Al salir del “trabajo” del día, haz algo diferente y deja de centrarte en la búsqueda de empleo por unas horas. 2. Rodéate de personas con trabajo. Puede parecer contradictorio, pero es más útil que juntarse con otros desempleados y compadecerse. Eso nos arrastra hacia el fondo. Procura pasar el tiempo con personas con trabajo. No solo te subirá el ánimo, sino que te pueden proporcionar pistas para encontrar trabajo. 3. Aprende algo nuevo. Acepta el reto de aprender algo que siempre has querido aprender pero para lo que nunca tuviste tiempo. Enfrentarte a este reto te mantendrá ocupado y aumentará la confianza en tí mismo. 4. Haz algún curso relacionado con tu trabajo. Esto mejorará tu currículum y te mantendrá ocupado al mismo tiempo. Busca cursos gratuitos para desempleados en tu campo de trabajo. 5. Respira, repite afirmaciones positivas. Muchas personas niegan la importancia de las técnicas de relajación, de la respiración o de la búsqueda consciente de la felicidad porque les parece algo cursi o que no sirve para nada. Sin embargo, funciona. Las afirmaciones voz alta o dedicar diez minutos por día para la respiración consciente te harán sentir mejor. 6. Evita las malas noticias. Las noticias sobre desahucio y tasas de desempleo no son buenas para ti en este momento. Las malas noticias producen un efecto negativo sobre nosotros. Lee un libro edificante o ve buenas películas en su lugar. 7. Haz ejercicio todos los días. Treinta minutos de ejercicio al día nos hacen sentir mejor física y mentalmente. El ejercicio moderado al aire libre aumenta las endorfinas también conocidas como hormonas de la felicidad. 8. Cuida la alimentación. De nuevo, los beneficios físicos redundan en el estado de la mente. Una alimentación sana y equilibrada nos hace sentir mejor. 9. Esfuérzate en hablar de lo que estás haciendo. Es fácil centrarse en hablar de lo frustrante que es buscar trabajo o de lo mal que está la situación económica. Es contraproducente y solo sirve para hundirnos más. Habla sobre lo que has estado haciendo, lo que has leído, lo que querías ser cuando eras un niño… Cualquier cosa positiva excepto de la búsqueda de trabajo. 10. Apóyate en las personas de tu confianza. Cuando los sentimientos negativos te abrumen, no te encierres. Ábrete a las personas de tu entorno que sean mejor apoyo en tiempos de difíciles. Estas personas no tienen porqué ser tu pareja o tu mejor amigo. Un amigo con menos implicación en tu bienestar puede ser un mejor oído en este momento. 11. Celebra las pequeñas cosas. La entrevista de trabajo quizá no ha salido bien, pero, al menos, has tenido una entrevista. Es difícil mantener una actitud positiva, pero hay que pensar que el esfuerzo que has realizado para hacerlo bien ya vale la pena. 12. Ponte metas diarias específicas. El mundo laboral en este momento está complicado, pero tú puedes alcanzar metas diarias relacionadas con la búsqueda de empleo. Establece unos objetivos diarios de búsqueda de empleo y cúmplelos. Tu autoestima se verá recompensada. 13. Haz un presupuesto. Esto puede ser frustrante cuando no hay ingresos pero, por lo menos, te da una cierta sensación de control sobre tus finanzas, lo cual puede hacerte sentir mejor a largo plazo. 14. Ve a algún lugar, a cualquiera, todos los días. Es muy fácil deprimirse quedándose en casa. Ve a tomar un café a un bar, a mirar escaparates o a dar una vuelta a la manzana. Para no caer en la depresión hay que esforzarse en hacer lo contrario a lo que apetece: hablar, salir, divertirse…. 15. No descartar la ayuda de un profesional. Si estás comenzando a sufrir depresión a causa del desempleo plantéate la posibilidad de buscar la ayuda de un psicólogo o un psiquiatra. Harán que te sientas mejor. Comparto una app autoayuda', 'https://erbolamm.blogspot.com/2020/09/app-es-feliz-no-me-descargue.html', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('ce198f50-3d9a-4b37-a194-e5f3e15bccfd', NULL, 'Ayuda 200€', 'El gobierno ha activado la ayuda de 200€, solo tienes que poner en google agencia tributaria 200€ o seguir el enlace que dejo debajo y empezar a rellenar', 'https://sede.agenciatributaria.gob.es/Sede/procedimientoini/GC51.shtml', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('7b22844c-c3c6-47a4-a31b-511a192809b3', NULL, 'CERTIFICADO DIGITAL', '¿Para qué sirve el certificado digital?La principal ventaja del certificado digital es que nos ahorrará tiempo y dinero al permitir realizar trámites administrativos a través de Internet, a cualquier hora y en cualquier lugar. Además, vamos a necesitarlo si queremos cumplir con nuestras obligaciones tributarias ya que la mayoría de los modelos debemos presentarlos electrónicamente.Los trámites que podremos realizar con el certificado digital son los siguientes: Presentación y liquidación de impuestos.Presentación de recursos y reclamaciones.Cumplimentación de los datos del censo de población y viviendas.Consulta e inscripción en el padrón municipal.Consulta de multas de circulación.Consulta y trámites para solicitud de subvenciones.Consulta de asignación de colegios electorales.Actuaciones comunicadas.Firma electrónica de documentos y formularios oficiales.', 'https://www.tramitescertificadodigital.com/?gclid=CjwKCAiAirb_BRBNEiwALHlnD37Aq0_1R5Zzbo6hD1_QZwm8d41C7SSQH14GxmIdhRS8cVN42pXGZBoCTNYQAvD_BwE', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('e3920a14-788b-4de8-8f3f-5b5a4d94f800', NULL, '¿COMO PEDIR LA TARJETA? ¿ COMO SELLAR? ¿COMO RENOVAR?', '¿Cómo pedir la tarjeta del paro? Cada Comunidad Autónoma lo organiza de una manera En la mayoría basta con acudir a la oficina normalmente, pero hay algunas que tienen su propio sistema de citas previas (distinto de las del SEPE) para atender temas de su competencia: formación, tarjetas de demandas de empleo, etc. Yo sugiero que llamen a el teléfono fijo de la comunidad, que pueden encontrar en esta app y pregunten mejor desde ahí. El horario suele ser el típico de oficina de 9 a 14h y de 16 a 21h Si comprueban que no es así no duden en dejarme un mensaje.', NULL, NULL, TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('9e32a861-cd01-4b74-bf78-4cb191e958b3', NULL, '¿Cómo puedo anular una cita previa con el SEPE?', 'En caso de que nos haya surgido un imprevisto y tengamos que anular nuestra cita previa con el SEPE, debemos de seguir los siguientes pasos: 1.Al igual que para solicitarla, entra en la a Sede Electrónica del SEPE, pincha en personas y seguidamente en cita previa. 2.Ahora dale a Anulación de Cita. 3.Para terminar, introduce tu DNI y la fecha de tu cita y pulsa en confirmar para guardar la anulación.', NULL, NULL, TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('8bede6f6-06c5-496f-86e0-e2127352f5c8', NULL, '¿CÓMO PUEDO CONSULTAR EL ESTADO DE MI PRESTACIÓN POR DESEMPLEO?', 'El SEPE ha publicado esta guía rapida para consultar el estado de tu prestación por desempleo a través de la SEDE ELECTRÓNICA del Servicio Público de Empleo Estatal SEPE. Dentro de la SEDE ELECTRÓNICA debes dirigirte al apartado procedimientos y servicios y a la sección destinada a Personas. Sigue los pasos que verás en el enlace de mas abajo pulsando el globo.', 'https://sepe.es/HomeSepe/que-es-el-sepe/comunicacion-institucional/noticias/detalle-noticia.html?folder=/2020/Abril/&detail=como-puedo-consultar-estado-prestacion-desempleo', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('1de1079f-1570-49a8-800e-2dd159adeb79', NULL, '¿COMO RECUPERAR CONTRASEÑA?', 'He perdido mi contraseña. ¿Qué hago? Si usted ha olvidado su contraseña, solo tiene que dirigirse al apartado de inicio de sesión y ahí aparecerá un botón de "Recuperar contraseña", "Recordar la contraseña", "Olvidó la contraseña", o algo similar. Desde ahí tendrá que seguir los pasos que le indique poniendo su correo electrónico o DNI/NIE. A continuación recibirá un correo electrónico con un enlace que le dirigirá a una página web para crear una nueva contraseña. Depende de la comunidad autónoma también puede recibir una clave o un código para recuperarla.', NULL, NULL, TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('5f560b55-280d-46f1-b2bd-312ed29d66a8', NULL, '¿COMO SOLICITAR LA RECTIFICACIÓN DE ALGÚN DATO QUE TENGAS MAL EN TU PRESTACIÓN?', 'Dejo tal cual el mensaje que me ha enviado un usuario de la app donde explica y nos ayuda a rectificar datos de la prestación.... Nombre: Javier Ruiz Mensaje: https://sede.sepe.gob.es/SolicPrestIndividualWeb/flows/solicitud?execution=e1s1 Aquí te mando el enlace a la página del sepe donde puedes solicitar la rectificación de algún dato que tengas mal en tu prestación como puede ser incluir a los hijos que por defecto no vienen... Me tire buscándola una hora después de intentar ponerme en contacto con ellos por teléfono unas diez veces y siempre estaban ocupados, me mandaban a la página de internet y me colgaba, espero que le sirva a alguien... Un abrazo. DESDE LA APP Y CREO QUE HABLO EN NOMBRE DE TODOS LOS USUARIOS GRACIAS', 'https://sede.sepe.gob.es/SolicPrestIndividualWeb/flows/solicitud?execution=e1s1', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('9d15ebd4-40c8-4182-968a-523a876f802a', NULL, 'Consulta sobre subvenciones', 'Habilitado el acceso en #SedeElectrónica del SEPE para la solicitud y consulta sobre subvenciones del #PlandeRecuperacion Pulse en el botó de vista previa, recuerde que para ver el enlace fuera de la app pulse la barra superior al cargar la vista previa.', 'https://sede.sepe.gob.es/contacte/contacteInternet.do', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('a2a45c5c-09d5-47df-b2f6-a40ff3221d7c', NULL, 'ERRORES COMUNES AL SOLICITAR ERTES', 'GUÍA DE ERRORES NADIE DE LA EMPRESA HA COBRADO Posible causa No se ha remitido el excel Solución al problema Remitir el excel Dejo un pdf con más opciones Al pulsar en la imagen abrirá otra pantalla de la app, donde verá un vista previa del enlace, para verlo correctamente, pulse en la barra superior que encontrará en dicha pantalla, eso le sacará de la app LO RECOMIENDO', 'https://www.sepe.es/SiteSepe/contenidos/COVID-19/documentos/guia-errores-reconocimiento-prestaciones-erte.pdf', 'https://drive.mobincube.com/imgs/0ebd0b7ca58aed5a3c63d663781ea406', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('bef3e0d9-5607-4b7d-9fa1-2d93e19e28ce', NULL, 'Formulario para realizar una pre-solicitud', 'En la Sede electrónica del SEPE está disponible el formulario para realizar una pre-solicitud individual de prestación por desempleo y otros trámites. Para aquellas personas que no disponen de DNI electrónico, certificado digital o CL@VE permanente, se ha establecido un formulario de pre-solicitud desde el que se pueden realizar las solicitudes de trámites de protección por desempleo. Se pueden realizar los trámites que a continuación te indicamos 1. Desde el apartado de pre-solicitud de prestación individual podrás solicitar dicha prestación y realizar los sub-trámites siguientes: Solicitud de prestación contributiva. Solicitud de subsidio (alta, reanudación o prórroga). Declaración Anual de Rentas subsidio mayores de 52 años. Compatibilidad de trabajo a tiempo parcial o por cuenta propia. 2. En el apartado baja prestación, además de esta solicitud, se pueden realizar los siguientes subtrámites: Solicitud de baja por baja médica o IT Solicitud de baja por colocación por cuenta ajena o propia Solicitud de baja por maternidad/paternidad Solicitud de baja por salida de España Solicitud de baja de subsidio por cambios en rentas o responsabilidades familiares Sigue este enlace para acceder al formulario de pre-solicitud.', 'https://sede.sepe.gob.es/SolicPrestIndividualWeb/flows/solicitud?execution=e1s1', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('50daed49-1391-4b00-98d8-c009af862057', NULL, '¿Ha visto algún error?', 'Por favor si ve que hay algún error en la app diríjase al icono con forma de sobre para ponerse en contacto conmigo', NULL, NULL, TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('3a1f427f-9f09-4d44-bcd8-f0db825b6f61', NULL, '¿HAS TRABAJADO MENOS DE UN AÑO?', 'Si usted ha trabajado menos de un año, puede acceder a un subsidio por desempleo, pero hay que tener en cuenta que la duración depende del número de meses cotizados y de si tiene o no responsabilidades familiares.', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/quiero-cobrar-el-paro/he-trabajado-menos-un-ano.html', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('99382380-8219-41ad-8064-90d839269e81', NULL, 'IMPORTANTE Comprueba si tiene la última versión de la app', 'ahora lo importante es comprobar si tiene instalada la ultima versión', 'https://mobincube.mobi/WRTRG', 'https://drive.mobincube.com/imgs/0ebd0b7ca58aed5a3c63d663781ea406', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('55e4d96e-8136-4bdb-a563-cd2ffe7d146e', NULL, 'Informe de vida laboral', 'A través de este servicio podrá obtener y/o consultar on-line un informe en el que se recogen todas las situaciones de alta o baja de una persona en el conjunto de los distintos regímenes del sistema de la Seguridad Social.pincha en el siguiente logo para acceder', 'https://sede.seg-social.gob.es/wps/portal/sede/sede/Ciudadanos/CiudadanoDetalle/!ut/p/z1/xZVRc6IwEMe_SvvgY8wmISTcG-30rFbr2NZWeXFCCMqdoAWutv30F2zn7uZ6gDN25nzAIVn-u_z-2QUHeIaDTD0lS1Umm0yt7f08cBeMuA7xgAx70L8Afzq6mnpswnp9gh_2AVDz8wEHzc_f4wAHOiu35QrPCxOZhd5kpcmSaFN0oFrogE5-RCpSWbWSZPEmT01x8nKiTV4mcaLVPpQCka5TqW11EuF5REKpOBMoJowjR2iNQiEM8rgnYpeq2CHhe_U15YHXWv1Dla9FYR_QBKgxCXVbAnyOBzhYrjfhm11-FjK5xEFuYpObvPsjt8urstx-6UAHdrtdtzBLVGx0otZdY8H1Le48M-WCVHQj89xdlem_lFabosSzDwp4biGKP-q7mp7Z-r6OPWcqKICl9JSYHZ5m1jhb4-1vjywAFVLQiEbAkOOEMfKUEyLhhARYqAXnDF9CWwZ2ZIY3eT6WQAZAh-COJPje5HY6vCYMhDhSftDmn2VN89H5yLLeqnKFqjOOZzUnHc-A1G7hefLt8THwbUtVXfRs_arpKZNuc1Oopo6qz_OXHwA9e5KtJ7f3QAn0GvzwDIlibglxVXUllQ6SRlNEtQEaxZJzrj7YTSa8kh_L_s2EgBSfIl9rt3Ok_KCtn_-H3QeN0IMN75EzB3wyvnPp5QWBcQOyg8ZwoyO9pglykPygbYx_Nsj3b1ELNbf-tXRsQld7AgmqADnGXjyPURRTKb2QCRkJ2kaNHinfTG3CPnnaUHBdQfA2naaSvaDvN5evQ_OA5oOn3e4uTs9D-fLMQ75MF6MLtv8r3rZfz65R8GtjvTw9_QnsuQe6/dz/d5/L2dBISEvZ0FBIS9nQSEh/', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('c518a2dd-1042-4d06-a919-79f8afeb4613', NULL, 'Lector dni recomendado', 'Os dejo un lector de DNI ya que me han pedido por correo recomendarles uno solo tenéis que enchufarlo en el puerto usb cuando os pida en sepe.es la forma de acceder introducís en el lector el DNI. Para activar el DNI tenéis que ir a la comisaria de policía nacional mas cercana y seguir los pasos que os indica una maquina como la de la foto pulsando en la foto os lleva al lector que os recomiendo', 'https://amzn.to/2MYGV3E', 'https://drive.mobincube.com/imgs/eb144ab25ccf029715d2262698ad07c1', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('d22ab67a-3eeb-4b59-9b9a-0cce092a9a80', NULL, 'Pre-solicitud de prestación individual y otros trámites', 'Te recordamos que puedes solicitar tu prestación por desempleo vía telemática sin necesidad de Cl@ve permanente o firma electrónica a través de PRE-SOLICITUD Accede a la PRE-SOLICITUD', 'https://sede.sepe.gob.es/SolicPrestIndividualWeb/flows/solicitud?execution=e1s1', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('1e925987-192c-407f-940b-5c6e981e4263', NULL, 'Protección por desempleo', 'Solicite y reconozca su prestación contributiva Registro electrónico No válido para ERTE COVID - 19 Solicite su prestación o subsidio por desempleo Registro electrónico No válido para ERTE COVID - 19 Formulario para pre-solicitud individual de prestaciones por desempleo Obtenga un certificado sobre su prestación Registro electrónico Pida cita previa para ser atendido por el SEPE Consulte los datos y recibo de su prestación Haga una simulación del cálculo de su prestación Realice la prórroga semestral de su subsidio Registro electrónico Realice la declaración anual de rentas (para subsidios mayores 52 años) Registro electrónico Modifique sus datos bancarios Registro electrónico Comunicación de variación de situación Personal, Familiar, Laboral o de Rentas Registro electrónico NUEVO Dé de baja su prestación Registro electrónico Realice el desistimiento de su solicitud Registro electrónico Realice la verificación de los documentos electrónicos', 'https://sede.sepe.gob.es/portalSede/procedimientos-y-servicios/personas/proteccion-por-desempleo.html', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('99b4788d-f66c-4bf4-b7f2-364838e16098', NULL, 'Solicite y reconozca', 'Solicite y reconozca su prestación contributiva Registro electrónico No válido para ERTE COVID - 19 Solicite su prestación o subsidio por desempleo Registro electrónico No válido para ERTE COVID - 19 Formulario para pre-solicitud individual de prestaciones por desempleo Obtenga un certificado sobre su prestación Registro electrónico Pida cita previa para ser atendido por el SEPE Consulte los datos y recibo de su prestación Haga una simulación del cálculo de su prestación Realice la prórroga semestral de su subsidio Registro electrónico Realice la declaración anual de rentas (para subsidios mayores 52 años) Registro electrónico Modifique sus datos bancarios Registro electrónico Comunicación de variación de situación Personal, Familiar, Laboral o de Rentas Registro electrónico NUEVO Dé de baja su prestación Registro electrónico Realice el desistimiento de su solicitud Registro electrónico Realice la verificación de los documentos electrónicos', 'https://sede.sepe.gob.es/portalSede/procedimientos-y-servicios/personas/proteccion-por-desempleo.html', 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEh5WBbcre9_DsSE9ANlCjFb1gpKfOffsCzq8pwiebJ3Bn2rT-B3Rb7COyXz6rwMZDwND4M3UGIod76xnWr6EehJAQl1SEatIQriHiPPeI13AwqzNfw3EnoYIJPeWGne-5RCLgUfiAyzBXFj8TFPKRCzBktjeOXaOqUsiSNVeQs-THP2548PhfFH0AqH_w/w128-h128-p-k-no-nu/VIST%20APREVIA.png', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('26b151db-3d41-4e9c-b6f5-c57421df2df4', NULL, 'Solicitud subvenciones', 'Habilitado el acceso en #SedeElectrónica del SEPE para la solicitud y consulta sobre subvenciones del #PlandeRecuperacion Pulse en el botó de vista previa, recuerde que para ver el enlace fuera de la app pulse la barra superior al cargar la vista previa.', 'https://sede.sepe.gob.es/portalSede/procedimientos-y-servicios/empresas/empleo.html', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('d0eca2b7-d6a5-4498-a0bc-f886a759af57', NULL, '¿TENGO DERECHO A VACACIONES ESTANDO COBRANDO UNA PRESTACIÓN POR DESEMPLEO?', 'Durante el periodo en el que está percibiendo prestaciones por desempleo no es un trabajador en activo, y por tanto, no tiene derecho a disfrutar de vacaciones. Además, mientras cobra prestaciones, ha de cumplir sus obligaciones de buscar activamente empleo, participar en acciones que incrementen sus posibilidades de trabajar y comparecer ante la entidad gestora cuando sea requerido para ello. No obstante lo anterior, tiene la posibilidad de salir al extranjero por tiempo no superior a quince días naturales por una sola vez cada año, siempre que ello no implique incumplimiento de sus obligaciones', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/FAQS/obligaciones-infracciones-sanciones/vacaciones-cobrando-prestacion.html', 'https://drive.mobincube.com/imgs/88ca347aa21aea3c8b5538d140a1ecfe', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('9869db59-afd8-4a1f-8542-0339fa305e4f', NULL, '¿TENGO DERECHO A VACACIONES ESTANDO COBRANDO UNAPRESTACIÓN POR DESEMPLEO?', 'Durante el periodo en el que está percibiendo prestaciones por desempleo no es un trabajador en activo, y por tanto, no tiene derecho a disfrutar de vacaciones. Además, mientras cobra prestaciones, ha de cumplir sus obligaciones de buscar activamente empleo, participar en acciones que incrementen sus posibilidades de trabajar y comparecer ante la entidad gestora cuando sea requerido para ello. No obstante lo anterior, tiene la posibilidad de salir al extranjero por tiempo no superior a quince días naturales por una sola vez cada año, siempre que ello no implique incumplimiento de sus obligaciones', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/FAQS/obligaciones-infracciones-sanciones/vacaciones-cobrando-prestacion.html', 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEh5WBbcre9_DsSE9ANlCjFb1gpKfOffsCzq8pwiebJ3Bn2rT-B3Rb7COyXz6rwMZDwND4M3UGIod76xnWr6EehJAQl1SEatIQriHiPPeI13AwqzNfw3EnoYIJPeWGne-5RCLgUfiAyzBXFj8TFPKRCzBktjeOXaOqUsiSNVeQs-THP2548PhfFH0AqH_w/w128-h128-p-k-no-nu/VIST%20APREVIA.png', TRUE, 'aprobado');
INSERT INTO consejos (id, id_autor, titulo, cuerpo, web, imagen_url, activo, estado_moderacion) VALUES ('d75d4519-f04d-4fa3-83c4-7e6465f2b933', NULL, 'Truco para pedir cita', 'Me comenta una usuaria de la app una solución para cuando sale el error... ----En estos momentos no podemos ofrecerle citas en la oficina seleccionada. Puede hacer sus gestiones a través de la sede electrónica del Servicio Público de Empleo Estatal: www.sepe.es Para solicitar prestaciones, darse de baja en la prestación o modificar la cuenta bancaria pulse aquí: Formulario---- Resulta que esta usuaria de la app, se dedica a avisar cuando ve que se puede acceder, o sea la gente en un grupo de facebook lo comenta y ella se ofrece a hacer lo siguiente, tal y como ella misma me explicó: -.Yo entro desde muy temprano sobre las 7 menos algo. Cada 10 min. Hasta que veo que ponen las citas Y allí aviso a los que tengo en lista y envío un mensaje donde digo "ahora" ellos en ese momento se conectan y cogen su cita. Bien, yo desde aquí quiero darle las gracias por su labor desinteresada ayudando a las personas de su municipio, ya que al igual que yo, mucha de las veces, incluso le protestan pensando que trabaja para el SEPE cuando no es así, y solo se dedica a ayudar. Me pidió dejarla en el anonimato, evidentemente jajajajaj, y se de sobra lo que es recibir correos diarios incluso con insultos pensando que trabajo para el SEPE o INEM Repito, desde aquí GRACIAS INFINITAS Creo que en el nombre de todos los usuarios de la app. EN RESUMEN: Si veis que os aparece ese mensaje cuando quieren pedir una cita, insistan y sobre todo temprano. Ojo no sabemos si vale para toda España, pero está claro que aquí en la costa de donde soy esta funcionando', NULL, NULL, TRUE, 'aprobado');
