INSERT INTO prestaciones (titulo, descripcion, requisitos, url, activo) VALUES ('Subsidio para mayores de 52 años', 'Ayuda hasta la jubilación para mayores de 52 que han agotado el paro. Cotiza para jubilación.', '{"age:over_52","status:exhausted","income:low"}', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/he-dejado-de-cobrar-el-paro.html', TRUE);
INSERT INTO prestaciones (titulo, descripcion, requisitos, url, activo) VALUES ('Ayuda Familiar (Con Cargas)', 'Para quienes han agotado el paro y tienen responsabilidades familiares.', '{"family:true","status:exhausted","income:low"}', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/he-dejado-de-cobrar-el-paro.html', TRUE);
INSERT INTO prestaciones (titulo, descripcion, requisitos, url, activo) VALUES ('Subsidio Mayores 45 sin cargas', 'Para mayores de 45 años que han agotado el paro y NO tienen cargas.', '{"age:45_51","age:over_52","family:false","status:exhausted","income:low"}', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/he-dejado-de-cobrar-el-paro.html', TRUE);
INSERT INTO prestaciones (titulo, descripcion, requisitos, url, activo) VALUES ('Renta Activa de Inserción (RAI)', 'Para parados de larga duración (+12 meses), discapacidad o violencia de género.', '{"Tener menos de 65 años.","No tener ingresos propios superiores al 75% del SMI.","Ser desempleado de larga duración (más de 45 años).","O ser víctima de violencia de género, emigrante retornado o persona con discapacidad."}', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/he-dejado-de-cobrar-el-paro.html', TRUE);
INSERT INTO prestaciones (titulo, descripcion, requisitos, url, activo) VALUES ('Subsidio Extraordinario (SED)', 'El último recurso si has agotado todas las demás ayudas.', '{"Haber agotado cualquier subsidio por desempleo.","Ser desempleado de larga duración inscrito antes del 01/05/2018.","Tener cargas familiares.","No haber percibido antes el PAE."}', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/he-dejado-de-cobrar-el-paro.html', TRUE);
INSERT INTO prestaciones (titulo, descripcion, requisitos, url, activo) VALUES ('Subsidio Cotización Insuficiente', 'Si has trabajado menos de un año y no tienes derecho a paro.', '{"status:never","income:low"}', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/no-he-trabajado-mas-de-un-ano.html', TRUE);
INSERT INTO prestaciones (titulo, descripcion, requisitos, url, activo) VALUES ('Víctimas Violencia Género', 'Programa de inserción y ayuda económica específica.', '{"special:violence"}', 'https://www.sepe.es/HomeSepe/Personas/distributiva-prestaciones/he-dejado-de-cobrar-el-paro.html', TRUE);
